import sys

class Solution:
    def solve(self, num: str, set_: list[str]) -> int:
        count = 0
        for bit in set_:
            if (int(num, 2) & int(bit, 2)) == int(bit, 2):
                count += 1
        return count

if __name__ == '__main__):
    num = input()[:]
    set_ = input().split()[:
    solution = Solution()
    print(solution.solve(num, set_))

